    signature: 'isDead = UnitIsDead("unit")',
    parameters: [
      { name: 'unit', type: 'string', description: 'A unit to query', optional: false },
    ],
    returns: [
      { name: 'isDead', type: '1nil', description: '1 if the unit is dead; otherwise nil' },
    ],
    examples: [
      { title: 'Example', code: `-- Scan your party or raid and count how many people are dead
local maxNum = GetNumRaidMembers()
local unitType = "raid"
if maxNum <= 0 then
  maxNum = GetNumPartyMembers()
  unitType = "party"
end

if maxNum > 0 then
  local deadCount = 0
  for i=1,maxNum do
    if UnitIsDead(unitType .. i) then
      deadCount = deadCount + 1
    end
  end
  
  print("There are " .. deadCount .. " people dead in your " .. unitType)
else
  print("You are not in a party or raid")
end`, language: 'lua' },
    ],
